package com.wherefood.web;
import com.wherefood.domain.*; import net.coobird.thumbnailator.Thumbnails; import org.springframework.beans.factory.annotation.Value; import org.springframework.stereotype.Service; import org.springframework.web.multipart.MultipartFile; import software.amazon.awssdk.auth.credentials.*; import software.amazon.awssdk.core.sync.RequestBody; import software.amazon.awssdk.regions.Region; import software.amazon.awssdk.services.s3.*; import software.amazon.awssdk.services.s3.model.*; import javax.imageio.ImageIO; import java.awt.image.BufferedImage; import java.io.*; import java.net.URI; import java.time.Instant; import java.util.*;
@Service public class PhotoStorage { private final S3Client client; private final String bucket,publicUrl; public PhotoStorage(@Value("${app.storage.endpoint}")String endpoint,@Value("${app.storage.public-url}")String publicUrl,@Value("${app.storage.access-key}")String access,@Value("${app.storage.secret-key}")String secret,@Value("${app.storage.bucket}")String bucket){this.bucket=bucket;this.publicUrl=publicUrl.replaceAll("/$","");client=S3Client.builder().endpointOverride(URI.create(endpoint)).region(Region.US_EAST_1).forcePathStyle(true).credentialsProvider(StaticCredentialsProvider.create(AwsBasicCredentials.create(access,secret))).build();}
 public ItemPhoto store(Item item,MultipartFile upload)throws IOException {if(upload.getSize()>10*1024*1024)throw new org.springframework.web.server.ResponseStatusException(org.springframework.http.HttpStatus.PAYLOAD_TOO_LARGE,"Máximo 10 MB");BufferedImage image=ImageIO.read(upload.getInputStream());if(image==null)throw new org.springframework.web.server.ResponseStatusException(org.springframework.http.HttpStatus.BAD_REQUEST,"La foto debe ser una imagen válida");String root="items/"+item.id+"/"+UUID.randomUUID();byte[] full=render(image,1600);byte[] thumb=render(image,480);put(root+".webp",full);put(root+"-thumb.webp",thumb);ItemPhoto photo=new ItemPhoto();photo.item=item;photo.objectKey=root+".webp";photo.thumbnailKey=root+"-thumb.webp";photo.width=image.getWidth();photo.height=image.getHeight();photo.createdAt=Instant.now();return photo;}
 private byte[] render(BufferedImage image,int max)throws IOException {var out=new ByteArrayOutputStream();Thumbnails.of(image).size(max,max).outputFormat("webp").outputQuality(.82).toOutputStream(out);return out.toByteArray();} private void put(String key,byte[] bytes){client.putObject(PutObjectRequest.builder().bucket(bucket).key(key).contentType("image/webp").cacheControl("public, max-age=31536000, immutable").build(),RequestBody.fromBytes(bytes));} public String url(String key){return publicUrl+"/"+key;}
}
